### Step 6: Create `frontend/src/lib/verify-integrity.ts`

```typescript
import type { SkillListing, PurchaseReceipt, IntegrityVerification } from "./types";

const INITIAL_STATE: IntegrityVerification = {
  status: 'idle',
  rootHashMatch: null,
  blobIdMatch: null,
  receiptBlobIdMatch: null,
  derivedRootHash: null,
  derivedBlobId: null,
  onChainRootHash: null,
  onChainBlobId: null,
  receiptBlobId: null,
  verifiedAt: null,
  error: null,
  errorType: null,
};

export async function verifyBlobIntegrity(
  encryptedBytes: Uint8Array,
  skill: SkillListing,
  receipt: PurchaseReceipt,
): Promise&lt;IntegrityVerification&gt; {
  // No integrity data for quilts or pre-integrity listings
  if (!skill.rootHash) {
    return {
      ...INITIAL_STATE,
      status: 'verified',
      error: 'Integrity data not available for this listing',
      onChainBlobId: skill.walrusBlobId,
      receiptBlobId: receipt.walrusBlobId || null,
    };
  }

  try {
    const { WalrusClient } = await import("@mysten/walrus");
    const walrusClient = new WalrusClient({ network: "testnet" });
    const metadata = await walrusClient.computeBlobMetadata({ bytes: encryptedBytes });

    const derivedRootHash = Array.from(new Uint8Array(metadata.rootHash))
      .map(b => b.toString(16).padStart(2, '0'))
      .join('');
    const derivedBlobId = metadata.blobId;

    const rootHashMatch = derivedRootHash === skill.rootHash;
    const blobIdMatch = derivedBlobId === skill.walrusBlobId;
    const receiptBlobIdMatch = !receipt.walrusBlobId || receipt.walrusBlobId === skill.walrusBlobId;

    const allMatch = rootHashMatch && blobIdMatch && receiptBlobIdMatch;

    return {
      status: allMatch ? 'verified' : 'failed',
      rootHashMatch,
      blobIdMatch,
      receiptBlobIdMatch,
      derivedRootHash,
      derivedBlobId,
      onChainRootHash: skill.rootHash,
      onChainBlobId: skill.walrusBlobId,
      receiptBlobId: receipt.walrusBlobId || null,
      verifiedAt: new Date(),
      error: allMatch ? null : 'Content integrity verification failed — data may have been tampered with',
      errorType: allMatch ? null : 'inconsistent',
    };
  } catch (err) {
    return {
      ...INITIAL_STATE,
      status: 'failed',
      onChainRootHash: skill.rootHash,
      onChainBlobId: skill.walrusBlobId,
      receiptBlobId: receipt.walrusBlobId || null,
      error: err instanceof Error ? err.message : 'Verification failed',
      errorType: 'unknown',
    };
  }
}
```

### Step 7: Create `frontend/src/hooks/use-verify-integrity.ts`

```typescript
"use client";

import { useMutation } from "@tanstack/react-query";
import { verifyBlobIntegrity } from "@/lib/verify-integrity";
import type { SkillListing, PurchaseReceipt } from "@/lib/types";

interface VerifyIntegrityArgs {
  encryptedBytes: Uint8Array;
  skill: SkillListing;
  receipt: PurchaseReceipt;
}

export function useVerifyIntegrity() {
  return useMutation({
    mutationFn: async (args: VerifyIntegrityArgs) => {
      return verifyBlobIntegrity(args.encryptedBytes, args.skill, args.receipt);
    },
  });
}
```

